// Parse file list from command output
const output = $input.item(0).json.stdout;
const files = output.split('\n').filter(f => f.trim() !== '');

// Categorize by file type and folder
const assetCategories = {
  blueprints: [],
  materials: [],
  staticMeshes: [],
  textures: [],
  maps: [],
  cpp: [],
  other: []
};

files.forEach(file => {
  if (file.includes('/Blueprints/')) assetCategories.blueprints.push(file);
  else if (file.includes('/Materials/')) assetCategories.materials.push(file);
  else if (file.includes('/StaticMeshes/') || file.includes('/Meshes/')) assetCategories.staticMeshes.push(file);
  else if (file.includes('/Textures/')) assetCategories.textures.push(file);
  else if (file.endsWith('.umap')) assetCategories.maps.push(file);
  else if (file.endsWith('.cpp') || file.endsWith('.h')) assetCategories.cpp.push(file);
  else assetCategories.other.push(file);
});

const timestamp = new Date().toISOString().replace(/[:.]/g, '-').slice(0, -5);

return {
  files,
  totalFiles: files.length,
  categories: assetCategories,
  timestamp,
  backupName: `UE5_Backup_${timestamp}`
};

// Create backup manifest
const manifest = {
  backupName: $json.backupName,
  timestamp: new Date().toISOString(),
  stats: {
    totalFiles: $json.totalFiles,
    archiveSize: $json.archiveSize || 'calculating...',
    categories: Object.entries($json.categories).map(([type, files]) => ({
      type,
      count: files.length,
      files: files.slice(0, 5) // Include first 5 files as sample
    }))
  },
  uploadedTo: ['Google Drive', 'Dropbox'],
  projectPath: '/home/user/UnrealProjects/MyGame',
  engineVersion: '5.3'
};

// Create human-readable summary
const summary = `
# UE5 Backup Report - ${new Date().toLocaleDateString()}

## Summary
- **Backup Name:** ${manifest.backupName}
- **Total Files:** ${manifest.stats.totalFiles}
- **Archive Size:** ${manifest.stats.archiveSize}
- **Cloud Locations:** Google Drive, Dropbox

## Files by Category
${manifest.stats.categories.map(cat => 
  `### ${cat.type} (${cat.count} files)\n${cat.files.map(f => `- ${f}`).join('\n')}`
).join('\n\n')}

## Backup Locations
- **Google Drive:** /UE5_Backups/${manifest.backupName}.tar.gz
- **Dropbox:** /UE5_Backups/${manifest.backupName}.tar.gz
- **Local:** /tmp/${manifest.backupName}.tar.gz

---
*Generated: ${new Date().toISOString()}*
`;

return {
  manifest,
  summary
};
